#!/usr/bin/env python3
"""Strict double-cross-fitted M2 + coarse-pose C2 linear stack.

For every fixed outer whole-parent fold, base predictions used to fit the
meta-head are generated by the frozen inner whole-parent folds.  The outer
score parents are never used for base selection or meta fitting.
"""

from __future__ import annotations

import argparse
import csv
import hashlib
import json
from collections import defaultdict
from pathlib import Path
from typing import Dict, List, Mapping, Sequence, Tuple

import numpy as np

from evaluate_nested_oof_challengers_v1 import (
    PCA_EXCLUSIONS,
    evaluate_predictions,
    exact_min,
    feature_matrix,
    hierarchical_weights,
    read_tsv,
    ridge_predict,
    selection_loss,
    target_matrix,
    unique_rows,
)
from pca8_fold_transformer_v1 import fit_pca8, transform_pca8


MODEL_M2 = "M2_FROZEN_ALPHA10"
MODEL_C2 = "C2_INNER_SELECTED_PCA8_RIDGE"
MODEL_STACK = "M2_C2_NONNEGATIVE_SHARED_SLOPE_STACK"


def sha256_file(path: Path) -> str:
    digest = hashlib.sha256()
    with path.open("rb") as handle:
        for block in iter(lambda: handle.read(1024 * 1024), b""):
            digest.update(block)
    return digest.hexdigest()


def m2_hierarchical_weights(
    candidate_ids: Sequence[str], metadata: Mapping[str, Mapping[str, str]],
) -> np.ndarray:
    """Frozen M2 weighting: 0.5/source -> equal parent -> equal candidate."""
    groups: Dict[str, Dict[str, List[int]]] = defaultdict(lambda: defaultdict(list))
    for index, candidate in enumerate(candidate_ids):
        row = metadata[candidate]
        groups[row["teacher_source"]][row["parent_framework_cluster"]].append(index)
    if len(groups) != 2:
        raise ValueError("M2 requires exactly two teacher sources")
    weights = np.zeros(len(candidate_ids), dtype=np.float64)
    for parents in groups.values():
        for indices in parents.values():
            weights[indices] = 0.5 / len(parents) / len(indices)
    if not np.isclose(weights.sum(), 1.0, atol=1e-14, rtol=0.0):
        raise ValueError("M2 hierarchical weights do not sum to one")
    return weights


def fit_m2_ridge(
    train_x: np.ndarray,
    train_y: np.ndarray,
    score_x: np.ndarray,
    weights: np.ndarray,
    alpha: float = 10.0,
) -> np.ndarray:
    """Reproduce the frozen V2.4 M2 Ridge implementation exactly."""
    normalized = weights / weights.sum()
    x_mean = np.sum(train_x * normalized[:, None], axis=0)
    x_scale = np.sqrt(np.sum((train_x - x_mean) ** 2 * normalized[:, None], axis=0))
    x_scale[x_scale < 1e-8] = 1.0
    y_mean = np.sum(train_y * normalized[:, None], axis=0)
    standardized = (train_x - x_mean) / x_scale
    root = np.sqrt(weights)[:, None]
    coefficient = np.linalg.solve(
        (standardized * root).T @ (standardized * root) + alpha * np.eye(train_x.shape[1]),
        (standardized * root).T @ ((train_y - y_mean) * root),
    )
    prediction = (score_x - x_mean) / x_scale @ coefficient + y_mean
    if prediction.shape != (len(score_x), 2) or not np.isfinite(prediction).all():
        raise ValueError("invalid M2 prediction")
    return prediction


def c2_predict(
    train_x: np.ndarray,
    train_y: np.ndarray,
    score_x: np.ndarray,
    weights: np.ndarray,
    alpha: float,
) -> np.ndarray:
    """Fit C2 scaler/filter/PCA8 on this training fold only, then Ridge."""
    pca = fit_pca8(train_x, components=8)
    train_pca = transform_pca8(train_x, pca)
    score_pca = transform_pca8(score_x, pca)
    return ridge_predict(train_pca, train_y, score_pca, weights, alpha)


def fit_nonnegative_shared_slope(
    truth_two: np.ndarray,
    m2_two: np.ndarray,
    c2_two: np.ndarray,
    weights: np.ndarray,
    penalty: float,
) -> Tuple[float, Dict[str, float]]:
    """Fit one convex C2 slope shared by R8/R9 and shrunk toward M2."""
    if truth_two.shape != m2_two.shape or truth_two.shape != c2_two.shape:
        raise ValueError("meta-head shape mismatch")
    if truth_two.ndim != 2 or truth_two.shape[1] != 2:
        raise ValueError("meta-head requires two receptor outputs")
    if weights.shape != (len(truth_two),) or penalty <= 0:
        raise ValueError("invalid meta-head weights or penalty")
    delta = c2_two - m2_two
    residual = truth_two - m2_two
    numerator = float(np.sum(weights[:, None] * delta * residual))
    data_denominator = float(np.sum(weights[:, None] * delta * delta))
    raw = numerator / (data_denominator + penalty)
    c2_weight = float(np.clip(raw, 0.0, 1.0))
    return c2_weight, {
        "numerator": numerator,
        "data_denominator": data_denominator,
        "penalty": float(penalty),
        "raw_c2_weight": raw,
        "c2_weight": c2_weight,
        "m2_weight": 1.0 - c2_weight,
    }


def stack_predict(m2_two: np.ndarray, c2_two: np.ndarray, c2_weight: float) -> np.ndarray:
    if not 0.0 <= c2_weight <= 1.0:
        raise ValueError("C2 meta weight violates convex constraint")
    result = (1.0 - c2_weight) * m2_two + c2_weight * c2_two
    if not np.isfinite(result).all():
        raise ValueError("non-finite stack prediction")
    return result


def prediction_rows(
    model_id: str,
    outer_fold: int,
    candidate_ids: Sequence[str],
    truth_two: np.ndarray,
    prediction_two: np.ndarray,
    metadata: Mapping[str, Mapping[str, str]],
    c2_alpha: float,
    c2_weight: str | float,
) -> List[Dict[str, object]]:
    rows = []
    for index, candidate in enumerate(candidate_ids):
        rows.append({
            "model_id": model_id,
            "candidate_id": candidate,
            "outer_fold": outer_fold,
            "teacher_source": metadata[candidate]["teacher_source"],
            "parent_framework_cluster": metadata[candidate]["parent_framework_cluster"],
            "selected_c2_alpha": c2_alpha,
            "meta_c2_weight": c2_weight,
            "truth_R8": truth_two[index, 0],
            "truth_R9": truth_two[index, 1],
            "truth_Rdual": min(truth_two[index]),
            "pred_R8": prediction_two[index, 0],
            "pred_R9": prediction_two[index, 1],
            "pred_Rdual": min(prediction_two[index]),
        })
    return rows


def require_prediction_closure(rows: Sequence[Mapping[str, object]], candidates: set[str]) -> None:
    for model_id in (MODEL_M2, MODEL_C2, MODEL_STACK):
        subset = [row for row in rows if row["model_id"] == model_id]
        if len(subset) != len(candidates) or {str(row["candidate_id"]) for row in subset} != candidates:
            raise ValueError(f"prediction closure failed:{model_id}")
        if any(
            abs(float(row["pred_Rdual"]) - min(float(row["pred_R8"]), float(row["pred_R9"]))) > 1e-12
            for row in subset
        ):
            raise ValueError(f"exact-min violation:{model_id}")


def main(args: argparse.Namespace) -> None:
    contract_path = Path(args.contract).resolve()
    contract = json.loads(contract_path.read_text())
    if contract["status"] != "PREREGISTERED_BEFORE_STACK_PERFORMANCE_COMPUTATION":
        raise ValueError("stack contract is not preregistered")

    labels = unique_rows(read_tsv(Path(args.labels)), "label")
    raw = unique_rows(read_tsv(Path(args.raw_features)), "raw coarse-pose")
    candidates = set(labels)
    if len(candidates) != 1507 or set(raw) != candidates:
        raise ValueError("open1507 input closure failed")
    if any("V4F" in candidate.upper() for candidate in candidates):
        raise ValueError("V4-F/test32 candidate detected")

    metadata = {
        candidate: {
            "teacher_source": labels[candidate]["teacher_source"],
            "parent_framework_cluster": labels[candidate]["parent_framework_cluster"],
        }
        for candidate in candidates
    }
    m2_fields = [field for field in next(iter(labels.values())) if "__" in field]
    c2_fields = [
        field for field in next(iter(raw.values()))
        if "__" in field and field not in PCA_EXCLUSIONS
    ]
    if len(m2_fields) != 126 or len(c2_fields) != 32:
        raise ValueError(f"feature dimension mismatch:M2={len(m2_fields)}:C2={len(c2_fields)}")

    outer_rows = read_tsv(Path(args.outer_manifest))
    inner_rows = read_tsv(Path(args.inner_manifest))
    alphas = [float(value) for value in contract["c2_branch"]["ridge_alpha_grid"]]
    m2_alpha = float(contract["m2_branch"]["ridge_alpha"])
    meta_penalty = float(contract["meta_head"]["fixed_l2_toward_m2"])

    all_predictions: List[Dict[str, object]] = []
    alpha_rows: List[Dict[str, object]] = []
    meta_rows: List[Dict[str, object]] = []

    for outer_fold in range(5):
        fold_rows = [row for row in outer_rows if int(row["outer_fold"]) == outer_fold]
        train_ids = sorted(row["candidate_id"] for row in fold_rows if row["candidate_role"] == "train")
        score_ids = sorted(row["candidate_id"] for row in fold_rows if row["candidate_role"] == "score")
        if set(train_ids) & set(score_ids) or set(train_ids) | set(score_ids) != candidates:
            raise ValueError(f"outer split closure failed:{outer_fold}")
        train_parents = {metadata[c]["parent_framework_cluster"] for c in train_ids}
        score_parents = {metadata[c]["parent_framework_cluster"] for c in score_ids}
        if train_parents & score_parents:
            raise ValueError(f"outer parent leakage:{outer_fold}")

        train_truth = target_matrix(train_ids, labels)
        score_truth = target_matrix(score_ids, labels)
        inner_m2: Dict[str, np.ndarray] = {}
        inner_c2_by_alpha: Dict[float, Dict[str, np.ndarray]] = {alpha: {} for alpha in alphas}

        for inner_fold in range(5):
            subset = [
                row for row in inner_rows
                if int(row["outer_fold"]) == outer_fold and int(row["inner_fold"]) == inner_fold
            ]
            inner_train = sorted(row["candidate_id"] for row in subset if row["candidate_role"] == "train")
            inner_score = sorted(row["candidate_id"] for row in subset if row["candidate_role"] == "score")
            if set(inner_train) & set(inner_score) or set(inner_train) | set(inner_score) != set(train_ids):
                raise ValueError(f"inner split closure failed:{outer_fold}:{inner_fold}")
            inner_train_parents = {metadata[c]["parent_framework_cluster"] for c in inner_train}
            inner_score_parents = {metadata[c]["parent_framework_cluster"] for c in inner_score}
            if inner_train_parents & inner_score_parents:
                raise ValueError(f"inner parent leakage:{outer_fold}:{inner_fold}")

            y_inner = target_matrix(inner_train, labels)
            m2_weight = m2_hierarchical_weights(inner_train, metadata)
            m2_pred = fit_m2_ridge(
                feature_matrix(inner_train, labels, m2_fields), y_inner,
                feature_matrix(inner_score, labels, m2_fields), m2_weight, m2_alpha,
            )
            c2_weight = hierarchical_weights(inner_train, metadata)
            c2_train_x = feature_matrix(inner_train, raw, c2_fields)
            c2_score_x = feature_matrix(inner_score, raw, c2_fields)
            for index, candidate in enumerate(inner_score):
                if candidate in inner_m2:
                    raise ValueError("inner M2 candidate scored twice")
                inner_m2[candidate] = m2_pred[index]
            for alpha in alphas:
                prediction = c2_predict(c2_train_x, y_inner, c2_score_x, c2_weight, alpha)
                for index, candidate in enumerate(inner_score):
                    if candidate in inner_c2_by_alpha[alpha]:
                        raise ValueError("inner C2 candidate scored twice")
                    inner_c2_by_alpha[alpha][candidate] = prediction[index]

        if set(inner_m2) != set(train_ids) or any(set(rows) != set(train_ids) for rows in inner_c2_by_alpha.values()):
            raise ValueError(f"inner OOF coverage failed:{outer_fold}")
        ordered = sorted(train_ids)
        ordered_truth = target_matrix(ordered, labels)
        alpha_losses = {
            alpha: selection_loss(
                ordered,
                ordered_truth,
                np.stack([inner_c2_by_alpha[alpha][candidate] for candidate in ordered]),
                metadata,
            )
            for alpha in alphas
        }
        best_loss = min(alpha_losses.values())
        selected_alpha = max(
            alpha for alpha, loss in alpha_losses.items() if abs(loss - best_loss) <= 1e-12
        )
        for alpha in alphas:
            alpha_rows.append({
                "outer_fold": outer_fold,
                "alpha": alpha,
                "inner_parent_macro_three_target_mae": alpha_losses[alpha],
                "selected": str(alpha == selected_alpha).lower(),
            })

        ordered_m2 = np.stack([inner_m2[candidate] for candidate in ordered])
        ordered_c2 = np.stack([inner_c2_by_alpha[selected_alpha][candidate] for candidate in ordered])
        meta_weight = m2_hierarchical_weights(ordered, metadata)
        learned_c2_weight, meta_audit = fit_nonnegative_shared_slope(
            ordered_truth, ordered_m2, ordered_c2, meta_weight, meta_penalty,
        )

        outer_m2_weight = m2_hierarchical_weights(train_ids, metadata)
        outer_m2 = fit_m2_ridge(
            feature_matrix(train_ids, labels, m2_fields), train_truth,
            feature_matrix(score_ids, labels, m2_fields), outer_m2_weight, m2_alpha,
        )
        outer_c2 = c2_predict(
            feature_matrix(train_ids, raw, c2_fields), train_truth,
            feature_matrix(score_ids, raw, c2_fields),
            hierarchical_weights(train_ids, metadata), selected_alpha,
        )
        outer_stack = stack_predict(outer_m2, outer_c2, learned_c2_weight)

        all_predictions.extend(prediction_rows(
            MODEL_M2, outer_fold, score_ids, score_truth, outer_m2, metadata,
            selected_alpha, "",
        ))
        all_predictions.extend(prediction_rows(
            MODEL_C2, outer_fold, score_ids, score_truth, outer_c2, metadata,
            selected_alpha, "",
        ))
        all_predictions.extend(prediction_rows(
            MODEL_STACK, outer_fold, score_ids, score_truth, outer_stack, metadata,
            selected_alpha, learned_c2_weight,
        ))
        meta_rows.append({
            "outer_fold": outer_fold,
            "inner_oof_candidates": len(ordered),
            "inner_oof_parents": len({metadata[c]["parent_framework_cluster"] for c in ordered}),
            "selected_c2_alpha": selected_alpha,
            **meta_audit,
        })

    require_prediction_closure(all_predictions, candidates)
    metrics = {
        model_id: evaluate_predictions([row for row in all_predictions if row["model_id"] == model_id])
        for model_id in (MODEL_M2, MODEL_C2, MODEL_STACK)
    }

    comparator = contract["promotion_gate"]
    m2_metric = metrics[MODEL_M2]["targets"]["R_dual_min"]
    expected = {
        "spearman": comparator["frozen_M2_Rdual_spearman"],
        "mae": comparator["M2_Rdual_mae_ceiling"],
        "rmse": comparator["M2_Rdual_rmse_ceiling"],
    }
    m2_reproduction = {
        key: abs(m2_metric[key] - expected[key]) <= 1e-12 for key in expected
    }
    m2_reproduction_pass = all(m2_reproduction.values())
    stack_metric = metrics[MODEL_STACK]["targets"]["R_dual_min"]
    source_nonregression = all(
        metrics[MODEL_STACK]["sources"][source]["R_dual_min"]["mae"]
        <= metrics[MODEL_M2]["sources"][source]["R_dual_min"]["mae"]
        for source in metrics[MODEL_STACK]["sources"]
    )
    parent_nonregression = (
        metrics[MODEL_STACK]["parent_macro"]["R_dual_min"]["macro_mae"]
        <= metrics[MODEL_M2]["parent_macro"]["R_dual_min"]["macro_mae"]
    )
    gates = {
        "M2_exact_reproduction": m2_reproduction_pass,
        "Rdual_spearman": stack_metric["spearman"] >= comparator["required_Rdual_spearman"],
        "Rdual_mae": stack_metric["mae"] <= comparator["M2_Rdual_mae_ceiling"],
        "Rdual_rmse": stack_metric["rmse"] <= comparator["M2_Rdual_rmse_ceiling"],
        "source_Rdual_mae_nonregression_vs_M2": source_nonregression,
        "parent_macro_Rdual_mae_nonregression_vs_M2": parent_nonregression,
    }
    status = "PASS_PROMOTE_M2_C2_STACK" if all(gates.values()) else "DO_NOT_PROMOTE_M2_C2_STACK"

    output_dir = Path(args.output_dir)
    output_dir.mkdir(parents=True, exist_ok=True)
    prediction_path = output_dir / "open1507_double_crossfit_predictions.tsv"
    with prediction_path.open("w", newline="") as handle:
        writer = csv.DictWriter(
            handle, fieldnames=list(all_predictions[0]), delimiter="\t", lineterminator="\n",
        )
        writer.writeheader(); writer.writerows(all_predictions)
    alpha_path = output_dir / "inner_c2_alpha_selection.tsv"
    with alpha_path.open("w", newline="") as handle:
        writer = csv.DictWriter(handle, fieldnames=list(alpha_rows[0]), delimiter="\t", lineterminator="\n")
        writer.writeheader(); writer.writerows(alpha_rows)
    meta_path = output_dir / "outer_meta_head_parameters.tsv"
    with meta_path.open("w", newline="") as handle:
        writer = csv.DictWriter(handle, fieldnames=list(meta_rows[0]), delimiter="\t", lineterminator="\n")
        writer.writeheader(); writer.writerows(meta_rows)

    metric_payload = {
        "schema_version": "pvrig_v2_5_m2_c2_strict_double_crossfit_stack_metrics_v1",
        "status": status,
        "models": metrics,
        "gates": gates,
        "M2_reproduction_fields": m2_reproduction,
        "stack_delta_vs_M2": {
            key: stack_metric[key] - m2_metric[key] for key in ("spearman", "mae", "rmse")
        },
        "meta_c2_weights": [float(row["c2_weight"]) for row in meta_rows],
        "contract_sha256": sha256_file(contract_path),
        "claim_boundary": contract["claim_boundary"],
    }
    metrics_path = output_dir / "METRICS.json"
    metrics_path.write_text(json.dumps(metric_payload, indent=2, sort_keys=True) + "\n")
    receipt = {
        "schema_version": "pvrig_v2_5_m2_c2_strict_double_crossfit_stack_receipt_v1",
        "status": status,
        "prediction_rows": len(all_predictions),
        "candidates_per_model": len(candidates),
        "models": [MODEL_M2, MODEL_C2, MODEL_STACK],
        "outer_folds": 5,
        "same_row_stacking_used": False,
        "v4_f_or_test32_access": False,
        "candidate_docking_pose_features": False,
        "exact_min_violations": 0,
        "shared_meta_slope": True,
        "nonnegative_convex_meta_weights": True,
        "artifacts": {
            "predictions": {"path": str(prediction_path), "sha256": sha256_file(prediction_path)},
            "alpha_selection": {"path": str(alpha_path), "sha256": sha256_file(alpha_path)},
            "meta_parameters": {"path": str(meta_path), "sha256": sha256_file(meta_path)},
            "metrics": {"path": str(metrics_path), "sha256": sha256_file(metrics_path)},
            "contract": {"path": str(contract_path), "sha256": sha256_file(contract_path)},
        },
        "claim_boundary": contract["claim_boundary"],
    }
    (output_dir / "RESULT_RECEIPT.json").write_text(json.dumps(receipt, indent=2, sort_keys=True) + "\n")


if __name__ == "__main__":
    parser = argparse.ArgumentParser(description=__doc__)
    parser.add_argument("--labels", required=True)
    parser.add_argument("--raw-features", required=True)
    parser.add_argument("--outer-manifest", required=True)
    parser.add_argument("--inner-manifest", required=True)
    parser.add_argument("--contract", required=True)
    parser.add_argument("--output-dir", required=True)
    main(parser.parse_args())
